import React, { type FC } from 'react';
import type { IKitsContainer } from '@lmb/kitsconcerto-types';
import {Alert, AlertText, FormControlError, FormControlErrorIcon, FormControlErrorText} from '@lmb/kitsconcertomobile';
import {isObject} from "lodash";
import {AlertCircleIcon} from "lucide-react-native";

const ErrorMessage: FC<Omit<IKitsContainer, 'id'>> = ({ errors, invalid }) => {
    if (!errors || !invalid) return null;

    const renderMessage = (message: string, index?: number) => (
        <FormControlError key={index}>
            <FormControlErrorIcon as={AlertCircleIcon} className="text-red-500"/>
            <FormControlErrorText className="text-red-500">
                {message}
            </FormControlErrorText>
        </FormControlError>
    );

    if (typeof errors === 'string') {
        return renderMessage(errors);
    }

    if (Array.isArray(errors)) {
        return (
            <>
                {errors.map((err, i) => renderMessage(err, i))}
            </>
        );
    }

    if (isObject(errors) && !('type' in errors)) {
        return (
            <>
                {Object.values(errors).map(
                    (err: any, i) =>
                        err?.message && renderMessage(err.message, i),
                )}
            </>
        );
    }

    return null;
};

export default ErrorMessage;
